class Recipe { public string Name; public ushort Temp; public ushort Speed; public Recipe(string n, ushort t, ushort s) { Name=n; Temp=t; Speed=s; } }

void LoadRecipe(Recipe r) {
    Plc.WriteHoldingRegister(100, r.Temp);
    Plc.WriteHoldingRegister(101, r.Speed);
    Print($"加载配方: {r.Name} — 温度{r.Temp/10.0}°C, 转速{r.Speed}RPM");
}

var recipeA = new Recipe("A产品", 850, 1500);
var recipeB = new Recipe("B产品", 1200, 3000);
LoadRecipe(recipeA);
Print($"验证: 温度={Plc.ReadHoldingRegister(100)/10.0}°C");
LoadRecipe(recipeB);
Print($"验证: 温度={Plc.ReadHoldingRegister(100)/10.0}°C");
